-- {"operators": "INNER_JOIN,AGGREGATE", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ITEM,STOCK", "ducklake": true}
SELECT s.S_W_ID, SUM(s.S_QUANTITY * i.I_PRICE) AS total_value, AVG(s.S_QUANTITY * i.I_PRICE) AS avg_line, MIN(s.S_QUANTITY) AS min_qty, MAX(s.S_QUANTITY) AS max_qty FROM STOCK s JOIN ITEM i ON s.S_I_ID = i.I_ID GROUP BY s.S_W_ID;
